/**
 * Prepara o app para EAS Build: copia o pacote shared para dentro de apps/mobile
 * para que o upload do EAS inclua todas as dependências (monorepo).
 * Rode de apps/mobile: npm run prepare-eas
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

// scripts/ está em apps/mobile/scripts → raiz do repo = 3 níveis acima
const mobileRoot = path.resolve(__dirname, '..');
const repoRoot = path.resolve(mobileRoot, '..', '..');
const sharedRoot = path.join(repoRoot, 'packages', 'shared');
const targetDir = path.join(mobileRoot, '.eas-shared');

function fail(msg) {
  console.error('prepare-eas: ' + msg);
  process.exit(1);
}

function copyRecursive(src, dest) {
  if (!fs.existsSync(src)) return;
  const stat = fs.statSync(src);
  if (stat.isDirectory()) {
    if (!fs.existsSync(dest)) fs.mkdirSync(dest, { recursive: true });
    for (const name of fs.readdirSync(src)) {
      copyRecursive(path.join(src, name), path.join(dest, name));
    }
  } else {
    fs.copyFileSync(src, dest);
  }
}

try {
  if (!fs.existsSync(sharedRoot)) {
    fail('pasta packages/shared não encontrada em: ' + sharedRoot);
  }
  const pkgPath = path.join(mobileRoot, 'package.json');
  if (!fs.existsSync(pkgPath)) {
    fail('package.json do app não encontrado em: ' + mobileRoot);
  }

  // 1. Build do shared (se dist não existir)
  const distIndex = path.join(sharedRoot, 'dist', 'index.js');
  if (!fs.existsSync(distIndex)) {
    console.log('Rodando build do shared...');
    const isWin = process.platform === 'win32';
    execSync('npm run build -w packages/shared', {
      cwd: repoRoot,
      stdio: 'inherit',
      shell: isWin,
    });
  }
  if (!fs.existsSync(distIndex)) {
    fail('build do shared não gerou dist/index.js');
  }

  // 2. Criar .eas-shared com dist e package.json
  if (fs.existsSync(targetDir)) {
    fs.rmSync(targetDir, { recursive: true });
  }
  fs.mkdirSync(targetDir, { recursive: true });
  copyRecursive(path.join(sharedRoot, 'dist'), path.join(targetDir, 'dist'));
  fs.copyFileSync(
    path.join(sharedRoot, 'package.json'),
    path.join(targetDir, 'package.json')
  );
  console.log('Copiado packages/shared para apps/mobile/.eas-shared');

  // 3. Atualizar package.json do app para usar file:./.eas-shared
  const pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf8'));
  if (!pkg.dependencies) pkg.dependencies = {};
  pkg.dependencies['@driver-profit/shared'] = 'file:./.eas-shared';
  fs.writeFileSync(pkgPath, JSON.stringify(pkg, null, 2) + '\n');
  console.log('package.json atualizado para usar .eas-shared');
  console.log('Agora rode: npx eas build -p android --profile preview');
  console.log('Depois, reverta com: npm run clean-eas');
} catch (err) {
  console.error('prepare-eas erro:', err.message || err);
  process.exit(1);
}
